"use client";

import { useEffect, useRef } from "react";
import { TOPIC_COLORS_HEX } from "./TopicBadge";
import type { Topic } from "@/lib/types";

// 1. Configuración de Coordenadas y Colores por Municipio
const MUNICIPIOS_CONFIG: Record<string, { coords: [number, number], color: string }> = {
  "Montería": { coords: [8.7479, -75.8814], color: "#3b82f6" },          // Azul
  "Cereté": { coords: [8.8833, -75.7900], color: "#10b981" },            // Esmeralda
  "Lorica": { coords: [9.2394, -75.8139], color: "#8b5cf6" },            // Violeta
  "Sahagún": { coords: [8.9472, -75.4444], color: "#f59e0b" },           // Ámbar
  "Montelíbano": { coords: [7.9794, -75.4178], color: "#06b6d4" },       // Cian
  "Puerto Libertador": { coords: [7.8888, -75.6714], color: "#6366f1" }, // Índigo
  "Tierralta": { coords: [8.1733, -76.0594], color: "#ef4444" },         // Rojo
  "Planeta Rica": { coords: [8.4131, -75.5839], color: "#f43f5e" },      // Rosa
  "Ciénaga de Oro": { coords: [8.8761, -75.6203], color: "#ec4899" },    // Rosado
  "Chinú": { coords: [9.1064, -75.3981], color: "#a855f7" },             // Púrpura
  "Caucasia": { coords: [7.981, -75.193], color: "#71717a" }             // Gris
};

interface Props {
  articles: any[];
}

export function BarriosMap({ articles }: Props) {
  const mapRef = useRef<HTMLDivElement>(null);
  const mapInstanceRef = useRef<any>(null);

  useEffect(() => {
    if (!mapRef.current) return;

    // Si ya existe el mapa, solo actualizamos los marcadores
    if (mapInstanceRef.current) {
      updateMarkers(mapInstanceRef.current);
      return;
    }

    // Carga dinámica de Leaflet para evitar errores de SSR
    import("leaflet").then((L) => {
      // Fix para iconos por defecto
      delete (L.Icon.Default.prototype as any)._getIconUrl;
      L.Icon.Default.mergeOptions({
        iconRetinaUrl: "https://unpkg.com/leaflet@1.9.4/dist/images/marker-icon-2x.png",
        iconUrl: "https://unpkg.com/leaflet@1.9.4/dist/images/marker-icon.png",
        shadowUrl: "https://unpkg.com/leaflet@1.9.4/dist/images/marker-shadow.png",
      });
      if (mapRef.current && (mapRef.current as any)._leaflet_id) {
        return; 
}
      const map = L.map(mapRef.current!, {
        center: [8.7479, -75.8814], 
        zoom: 8,
        scrollWheelZoom: false, // Evita que el mapa atrape el scroll de la página
      });

      mapInstanceRef.current = map;

      L.tileLayer("https://{s}.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}{r}.png", {
        attribution: '&copy; CARTO',
        maxZoom: 19,
      }).addTo(map);

      updateMarkers(map, L);
    });

    function updateMarkers(map: any, LLib?: any) {
      const L = LLib || (window as any).L;
      if (!L) return;

      // Limpiar marcadores previos para evitar duplicados
      map.eachLayer((layer: any) => {
        if (layer instanceof L.Marker || layer instanceof L.CircleMarker) {
          map.removeLayer(layer);
        }
      });

      // Agrupar por municipio
      const byCity = new Map<string, any[]>();
      articles.forEach(art => {
        const city = art.neighborhood || art.municipio;
        if (city && MUNICIPIOS_CONFIG[city]) {
          if (!byCity.has(city)) byCity.set(city, []);
          byCity.get(city)!.push(art);
        }
      });

      // Dibujar marcadores
      byCity.forEach((arts, cityName) => {
        const config = MUNICIPIOS_CONFIG[cityName];
        const color = config.color;

        const icon = L.divIcon({
          html: `
            <div style="
              background: ${color};
              color: white;
              border: 2px solid white;
              border-radius: 50%;
              width: 30px;
              height: 30px;
              display: flex;
              align-items: center;
              justify-content: center;
              font-size: 12px;
              font-weight: bold;
              box-shadow: 0 0 15px ${color}cc;
            ">
              ${arts.length}
            </div>
          `,
          className: "",
          iconSize: [30, 30],
        });

        // Popup con estilo oscuro
        let popupHtml = `
          <div style="min-width:200px; padding: 5px;">
            <strong style="color:white; font-size:14px; border-bottom:1px solid #334155; display:block; padding-bottom:5px; margin-bottom:8px;">
              ${cityName} (${arts.length} reportes)
            </strong>
        `;
        
        arts.slice(0, 99).forEach(a => {
          const topicColor = TOPIC_COLORS_HEX[a.topic as Topic] || "#94a3b8";
          popupHtml += `
            <div style="margin-bottom:10px;">
              <span style="color:${topicColor}; font-size:9px; font-weight:bold; text-transform:uppercase;">${a.topic || 'General'}</span><br/>
              <a href="${a.url}" target="_blank" style="color:#38bdf8; text-decoration:none; font-size:12px; line-height:1.2;">${a.title}</a>
            </div>
          `;
        });

        popupHtml += `</div>`;

        L.marker(config.coords, { icon })
          .bindPopup(popupHtml, { className: "cordoba-popup" })
          .addTo(map);
      });
    }

    return () => {
      // No removemos el mapa aquí para evitar parpadeos en cada actualización de artículos,
      // la lógica de updateMarkers se encarga de los datos.
    };
  }, [articles]);

  return (
    <div className="relative w-full">
      <link rel="stylesheet" href="https://unpkg.com/leaflet@1.9.4/dist/leaflet.css" />
      <style>{`
        .cordoba-popup .leaflet-popup-content-wrapper { 
          background: #0f172a; 
          border: 1px solid #1e293b; 
          color: #fff; 
          border-radius: 8px;
        }
          /* ESTA ES LA PARTE CLAVE: Define el alto máximo y el scroll */
          .cordoba-popup .leaflet-popup-content {
          max-height: 400px; /* Ajusta este valor a tu gusto */
          overflow-y: auto;  /* Habilita el deslizador vertical */
          margin: 13px;      /* Espaciado interno */
          padding-right: 5px;
        }
          /* Personalización de la barra de desplazamiento (opcional) */
          .cordoba-popup .leaflet-popup-content::-webkit-scrollbar {
          width: 6px;
        }
          .cordoba-popup .leaflet-popup-content::-webkit-scrollbar-thumb {
          background: #334155;
          border-radius: 10px;
        }

        .cordoba-popup .leaflet-popup-tip { background: #0f172a; }
        .leaflet-container { font-family: inherit; }
      `}</style>
      <div 
        ref={mapRef} 
        className="w-full h-[500px] rounded-xl border border-slate-800 shadow-2xl overflow-hidden bg-slate-950"
      />
    </div>
  );
}